  1	import { type FC, useMemo } from 'react';
  2	import { useWatch } from 'react-hook-form';
  3	
  4	import ExpandableReviewSection from '@components/ExpandableReviewSection/ExpandableReviewSection';
  5	import {
  6	  DescriptionList,
  7	  DescriptionListDescription,
  8	  DescriptionListGroup,
  9	  DescriptionListTerm,
 10	  Stack,
 11	  useWizardContext,
 12	} from '@patternfly/react-core';
 13	import { isEmpty } from '@utils/helpers';
 14	import { useForkliftTranslation } from '@utils/i18n';
 15	
 16	import { planStepNames, PlanWizardStepId } from '../../constants';
 17	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 18	import { NetworkMapFieldId, NetworkMapType } from '../network-map/constants';
 19	
 20	import NetworkMapReviewTable from './NetworkMapReviewTable';
 21	
 22	const NetworkMapReviewSectionInner: FC = () => {
 23	  const { t } = useForkliftTranslation();
 24	  const { control } = useCreatePlanFormContext();
 25	
 26	  const [netMapType, networkMap, existingNetMap, netMapName] = useWatch({
 27	    control,
 28	    name: [
 29	      NetworkMapFieldId.NetworkMapType,
 30	      NetworkMapFieldId.NetworkMap,
 31	      NetworkMapFieldId.ExistingNetworkMap,
 32	      NetworkMapFieldId.NetworkMapName,
 33	    ],
 34	  });
 35	
 36	  const noMappingsSelected = useMemo(() => {
 37	    if (!networkMap || isEmpty(networkMap)) {
 38	      return true;
 39	    }
 40	
 41	    // Check if we have any valid mappings (both source and target networks must be present)
 42	    const hasValidMapping = networkMap.some(
 43	      (mapping) =>
 44	        mapping?.[NetworkMapFieldId.SourceNetwork]?.name &&
 45	        mapping?.[NetworkMapFieldId.TargetNetwork]?.name,
 46	    );
 47	
 48	    return !hasValidMapping;
 49	  }, [networkMap]);
 50	
 51	  if (netMapType === NetworkMapType.Existing) {
 52	    return (
 53	      <DescriptionList isHorizontal horizontalTermWidthModifier={{ default: '18ch' }}>
 54	        <DescriptionListGroup>
 55	          <DescriptionListTerm>{t('Network map')}</DescriptionListTerm>
 56	          <DescriptionListDescription data-testid="review-network-map">
 57	            {existingNetMap?.metadata?.name}
 58	          </DescriptionListDescription>
 59	        </DescriptionListGroup>
 60	      </DescriptionList>
 61	    );
 62	  }
 63	
 64	  if (noMappingsSelected) {
 65	    return <>{t('No network mappings selected')}</>;
 66	  }
 67	
 68	  if (netMapName) {
 69	    return (
 70	      <Stack hasGutter>
 71	        <DescriptionList isHorizontal horizontalTermWidthModifier={{ default: '18ch' }}>
 72	          <DescriptionListGroup>
 73	            <DescriptionListTerm>{t('Network map name')}</DescriptionListTerm>
 74	            <DescriptionListDescription>{netMapName}</DescriptionListDescription>
 75	          </DescriptionListGroup>
 76	        </DescriptionList>
 77	
 78	        <NetworkMapReviewTable />
 79	      </Stack>
 80	    );
 81	  }
 82	
 83	  return <NetworkMapReviewTable />;
 84	};
 85	
 86	const NetworkMapReviewSection: FC = () => {
 87	  const { goToStepById } = useWizardContext();
 88	
 89	  return (
 90	    <ExpandableReviewSection
 91	      title={planStepNames[PlanWizardStepId.NetworkMap]}
 92	      testId="review-network-map-section"
 93	      onEditClick={() => {
 94	        goToStepById(PlanWizardStepId.NetworkMap);
 95	      }}
 96	    >
 97	      <NetworkMapReviewSectionInner />
 98	    </ExpandableReviewSection>
 99	  );
100	};
101	
102	export default NetworkMapReviewSection;

